NAT.example:
Rules:                  2
"Outbound-NAT" {
        from trust;
        to untrust;
        source any;
        destination any;
        service any;
        translate-to "src: dynamic-ip-and-port (ethernet1/1)";
}
"Inbound-Web" {
        from untrust;
        to dmz;
        source any;
        destination 203.0.113.10;
        service service-http;
        translate-to "dst: 10.0.10.10";
}

"Outbound-NAT" {
        source-translation: dynamic-ip-and-port
        interface: ethernet1/1
}

"Inbound-Web" {
        destination-translation:
                translated-address: 10.0.10.10
                translated-port: 8080
}

"Inbound-Web" {
        translate-to "dst: 10.0.10.10 port 8080";
}

TShark.example:
# Produces one JSON object per packet; pipe through jq for querying:
tshark -r in.pcap -T json | jq '.[] | ._source.layers | {src: .ip.ip_src, dst: .ip.ip_dst, proto: .frame["frame.protocols"]}'

